import { useRef, useEffect } from 'react';

export function CinematicVideo({ src }: { src: string }) {
  const videoRef = useRef<HTMLVideoElement>(null);
  const rafRef = useRef<number>(0);
  const FADE_DURATION = 0.5; // segundos

  useEffect(() => {
    const video = videoRef.current;
    if (!video) return;

    const tick = () => {
      const { currentTime, duration, style } = video;
      if (!duration) { rafRef.current = requestAnimationFrame(tick); return; }

      // Fade in no início
      if (currentTime < FADE_DURATION) {
        style.opacity = String(currentTime / FADE_DURATION);
      }
      // Fade out antes do fim
      else if (currentTime > duration - FADE_DURATION) {
        style.opacity = String((duration - currentTime) / FADE_DURATION);
      }
      // Visível no meio
      else {
        style.opacity = '1';
      }

      rafRef.current = requestAnimationFrame(tick);
    };

    const handleEnded = () => {
      video.style.opacity = '0';
      setTimeout(() => {
        video.currentTime = 0;
        video.play();
      }, 100);
    };

    video.addEventListener('ended', handleEnded);
    video.play().then(() => {
      rafRef.current = requestAnimationFrame(tick);
    });

    return () => {
      cancelAnimationFrame(rafRef.current);
      video.removeEventListener('ended', handleEnded);
    };
  }, []);

  return (
    <video
      ref={videoRef}
      src={src}
      muted
      playsInline
      style={{
        position: 'absolute',
        inset: 'auto 0 0 0',
        top: '300px',        // ajustar conforme layout
        width: '100%',
        height: 'auto',
        opacity: 0,
        objectFit: 'cover',
      }}
    />
  );
}

